#include <iostream>
#include <sstream>
#include <string>

int countLines(std::istream& in) {
    int count = 0;
    std::string line;
    while (std::getline(in, line)) {
        ++count;
    }
    return count;
}

int main() {
    std::string all_input;
    std::string line;
    while (std::getline(std::cin, line)) {
        all_input += line + "\n";
    }
    std::istringstream ss(all_input);
    std::cout << "Lines: " << countLines(ss) << "\n";
    return 0;
}

