#include <iostream>
#include <sstream>
#include <string>

void appendEntry(std::ostringstream& log, int index, const std::string& msg) {
    log << "[" << index << "] " << msg << "\n";
}

int main() {
    int n;
    std::cin >> n;
    std::cin.ignore();
    std::ostringstream log;
    for (int i = 1; i <= n; ++i) {
        std::string msg;
        std::getline(std::cin, msg);
        appendEntry(log, i, msg);
    }
    std::cout << log.str();
    return 0;
}
